1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Damage = { itemType: string; amount: number };
10	export type Incident = { cause: string; damages: Damage[] };
11	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
12	export type Step = QuoteStep | ClaimStep;
13	
14	export type Scenario = {
15	  customer: { yearsWithMHPCO: number };
16	  steps: Step[];
17	};
18	
19	export type QuoteResult = { premium: number };
20	export type ClaimResult = { payout: number; remainingCap: number };
21	export type StepResult = QuoteResult | ClaimResult;
22	export type ScenarioResult = { results: StepResult[] };
23	
24	const PROCESSING_FEE = 5;
25	// Premiums are accumulated in hundredths of a gold piece so we can apply
26	// percentage surcharges/discounts (10%, 15%, 20%, 30%, 50%) with integer math
27	// and round once at the end (avoids floating-point artifacts).
28	const HUNDREDTHS_PER_UNIT = 100;
29	
30	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	  rune: 25,
36	  moonstone: 25,
37	};
38	
39	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
40	const BLOCK_SIZE = 3;
41	const BLOCK_BASE_PREMIUM = 60;
42	
43	const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
44	
45	const sumBasePremiums = (items: Item[]): number =>
46	  items.reduce((sum, item) => sum + basePremium(item), 0);
47	
48	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
49	
50	const groupByType = (items: Item[]): Item[][] => {
51	  const groups: Record<string, Item[]> = {};
52	  for (const item of items) {
53	    (groups[item.type] ??= []).push(item);
54	  }
55	  return Object.values(groups);
56	};
57	
58	const componentGroupBasePremium = (group: Item[]): number =>
59	  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);
60	
61	const itemsBasePremium = (items: Item[]): number => {
62	  const components = items.filter(isComponent);
63	  const mains = items.filter((item) => !isComponent(item));
64	  const componentTotal = groupByType(components)
65	    .map(componentGroupBasePremium)
66	    .reduce((sum, premium) => sum + premium, 0);
67	  return sumBasePremiums(mains) + componentTotal;
68	};
69	
70	const roundUpHundredthsToUnits = (h: number): number => Math.ceil(h / HUNDREDTHS_PER_UNIT);
71	
72	// Modifier rates are expressed in hundredths-per-gold of base premium (i.e. percentage points).
73	// Item-specific modifiers attach to a single item's base premium.
74	// Policy-wide modifiers attach to the total base premium of the policy.
75	const CURSE_SURCHARGE = 50;
76	const HIGH_ENCHANTMENT_SURCHARGE = 30;
77	const HIGH_ENCHANTMENT_THRESHOLD = 5;
78	const FIRST_QUOTE_SURCHARGE = 10;
79	const LOYALTY_DISCOUNT = 20;
80	const LOYALTY_THRESHOLD_YEARS = 2;
81	const FOLLOWUP_DISCOUNT = 15;
82	
83	const itemModifierRate = (item: Item): number => {
84	  let rate = 0;
85	  if (item.cursed) rate += CURSE_SURCHARGE;
86	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) rate += HIGH_ENCHANTMENT_SURCHARGE;
87	  return rate;
88	};
89	
90	const itemSurchargeHundredths = (item: Item): number => basePremium(item) * itemModifierRate(item);
91	
92	const sumItemSurchargesHundredths = (items: Item[]): number =>
93	  items.reduce((sum, item) => sum + itemSurchargeHundredths(item), 0);
94	
95	type Customer = { yearsWithMHPCO: number };
96	
97	const policyModifierRate = (customer: Customer, quoteIndex: number): number => {
98	  let rate = FIRST_QUOTE_SURCHARGE;
99	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) rate -= LOYALTY_DISCOUNT;
100	  if (quoteIndex > 0) rate -= FOLLOWUP_DISCOUNT;
101	  return rate;
102	};
103	
104	const quote = (step: QuoteStep, customer: Customer, quoteIndex: number): QuoteResult => {
105	  const baseGold = itemsBasePremium(step.items);
106	  const baseHundredths = baseGold * HUNDREDTHS_PER_UNIT;
107	  const itemSurchargesHundredths = sumItemSurchargesHundredths(step.items);
108	  const policySurchargeHundredths = baseGold * policyModifierRate(customer, quoteIndex);
109	  const totalHundredths = baseHundredths + itemSurchargesHundredths + policySurchargeHundredths;
110	  return { premium: roundUpHundredthsToUnits(totalHundredths) + PROCESSING_FEE };
111	};
112	
113	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
114	  sword: 1000, amulet: 600, staff: 800, potion: 400, rune: 250, moonstone: 250,
115	};
116	const DEDUCTIBLE = 100;
117	const HIGH_ENCH_PAYOUT_THRESHOLD = 8;
118	
119	type Policy = { items: Item[]; cap: number };
120	
121	const insuranceSum = (items: Item[]): number =>
122	  items.reduce((sum, item) => sum + (INSURANCE_VALUE_BY_TYPE[item.type] ?? 0), 0);
123	
124	const findInsuredItem = (items: Item[], itemType: string): Item | undefined =>
125	  items.find((item) => item.type === itemType);
126	
127	const damagePayoutGold = (item: Item, damageAmount: number): number => {
128	  const reimbursed =
129	    (item.enchantment ?? 0) >= HIGH_ENCH_PAYOUT_THRESHOLD ? damageAmount / 2 : damageAmount;
130	  return Math.max(0, reimbursed - DEDUCTIBLE);
131	};
132	
133	const totalPayoutGold = (insuredItems: Item[], damages: Damage[]): number =>
134	  damages.reduce((sum, damage) => {
135	    const item = findInsuredItem(insuredItems, damage.itemType);
136	    return item ? sum + damagePayoutGold(item, damage.amount) : sum;
137	  }, 0);
138	
139	const countBy = <T>(items: T[], key: (item: T) => string): Record<string, number> =>
140	  items.reduce<Record<string, number>>((acc, item) => {
141	    const k = key(item);
142	    acc[k] = (acc[k] ?? 0) + 1;
143	    return acc;
144	  }, {});
145	
146	const validateDamageCounts = (policy: Policy, damages: Damage[]): void => {
147	  const insuredCounts = countBy(policy.items, (item) => item.type);
148	  const damageCounts = countBy(damages, (damage) => damage.itemType);
149	  for (const [itemType, dCount] of Object.entries(damageCounts)) {
150	    if (dCount > (insuredCounts[itemType] ?? 0)) {
151	      throw new Error(`claim has ${dCount} damages of type "${itemType}" but policy covers only ${insuredCounts[itemType] ?? 0}`);
152	    }
153	  }
154	};
155	
156	const claim = (step: ClaimStep, policy: Policy): ClaimResult => {
157	  validateDamageCounts(policy, step.incident.damages);
158	  const payout = Math.floor(totalPayoutGold(policy.items, step.incident.damages));
159	  policy.cap -= payout;
160	  return { payout, remainingCap: policy.cap };
161	};
162	
163	export const runScenario = (scenario: Scenario): ScenarioResult => {
164	  let quoteIndex = 0;
165	  const results: StepResult[] = [];
166	  const policies: Policy[] = [];
167	  for (const step of scenario.steps) {
168	    if (step.op === "quote") {
169	      results.push(quote(step, scenario.customer, quoteIndex));
170	      policies.push({ items: step.items, cap: 2 * insuranceSum(step.items) });
171	      quoteIndex += 1;
172	    } else {
173	      results.push(claim(step, policies[step.policy]));
174	    }
175	  }
176	  return { results };
177	};
